Good idea! Middleware in axum is built on top of tower layers and services. You can create custom layers that wrap requests/responses or just log basic info. Here’s an example of a logging middleware:

```rust
use axum::{
    routing::get,
    Router,
    extract::RequestParts,
};

async fn log_request<B>(mut req: RequestParts<B>) {
    println!("{} {}", req.method(), req.uri());
}

pub struct LoggingLayer;

impl<S> tower::Service<axum::http::Request<B>> for LoggingLayer {
    type Response = axum::http::Response<B>; // same as S's response type
    type Error = S::Error;
    #[allow(unused_variables)]
    fn poll_ready(&mut self, cx: &mut std::task::Context<'_>) -> std::future::Ready<Result<(), Self::Error>> {
        std::future::ready(Ok(()))
    }

    async fn call(&mut self, req: axum::http::Request<B>) -> Result<Self::Response, Self::Error> {
        log_request(req.into_parts()).await;
        let res = tower_service::ServiceExt::oneshot(self, req).await?;
        Ok(res)
    }
}

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/", get(|| async { "Hello, World!" }))
        .layer(LoggingLayer);

    axum::Server::bind(&"0.0.0.0:3000".parse().unwrap())
        .serve(app.into_make_service())
        .await
        .unwrap();
}
```

